// Монорепо:
// packages/
//   shared/     ← общие типы и утилиты
//   core/       ← бизнес-логика, зависит от shared
//   app/        ← приложение на Vite, зависит от core и shared

// Граф зависимостей:
// app → core → shared
// app → shared

// tsconfig.base.json — общие настройки для всех пакетов
{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "strict": true,
    "esModuleInterop": true,
    "isolatedModules": true,
    "skipLibCheck": true
  }
}

// tsconfig.json (корень монорепо)
{
  "files": [],
  "references": [
    { "path": "packages/shared" },
    { "path": "packages/core" },
    { "path": "packages/app" }
  ]
}

// Команды:
// tsc -b              → собрать всё (инкрементально)
// tsc -b --verbose    → с подробным выводом
// tsc -b --force      → полная пересборка
// tsc -b --clean      → удалить выходные файлы
